// higher_order
function multiplier(factor) {
  return (n) => n * factor;
}
const triple = multiplier(3);
console.log([1, 2, 3].map(triple));

Function<Integer, Function<Integer, Integer>> multiplier = factor -> n -> n * factor;
Function<Integer, Integer> triple = multiplier.apply(3);
List<Integer> result = Arrays.asList(1, 2, 3).stream()
  .map(triple::apply)
  .collect(Collectors.toList());
